// Normalize Open Interest Data
const oiData = $input.first().json;

// Extract price data (assumed to be injected or fetched separately)
const currentPrices = {
  BTC: oiData.btc_price || 0,
  ETH: oiData.eth_price || 0,
  SOL: oiData.sol_price || 0
};

const normalizeExchangeData = (exchangeData) => {
  const exchanges = {};
  let total = 0;

  if (exchangeData) {
    Object.entries(exchangeData).forEach(([ex, val]) => {
      exchanges[ex.toLowerCase()] = val;
      total += val;
    });
  }

  return { exchanges, total };
};

const detectRegime = (oiChange, priceChange) => {
  if (oiChange > 0 && priceChange > 0) return 'OI_RISING_PRICE';
  if (oiChange > 0 && priceChange < 0) return 'OI_FALLING_PRICE';
  if (oiChange < 0 && priceChange > 0) return 'SHORT_SQUEEZE';
  if (oiChange < 0 && priceChange < 0) return 'DELVERAGING';
  return 'NEUTRAL';
};

const symbols = ['BTC', 'ETH', 'SOL', 'BNB', 'XRP', 'ADA', 'DOGE', 'SOL'];
const normalizedOI = [];

symbols.forEach(symbol => {
  const symbolKey = symbol.toLowerCase();
  const oiSymbolData = oiData[symbolKey] || oiData[symbol] || {};

  const { exchanges, total: total_oi_usd } = normalizeExchangeData(oiSymbolData.exchanges || oiSymbolData);
  const oi_change_1h_pct = oiSymbolData.change_1h || 0;

  // Regime detection (price change simulated - in production, compare with previous price)
  const price = currentPrices[symbol] || 0;
  const priceChange = oiSymbolData.price_change_1h || 0;
  const regime = detectRegime(oi_change_1h_pct, priceChange);

  normalizedOI.push({
    symbol,
    exchanges,
    total_oi_usd,
    oi_change_1h_pct,
    regime,
    price,
    price_change_1h_pct: priceChange
  });
});

return [{ json: { oi_data: normalizedOI, timestamp: new Date().toISOString() } }];

// Normalize Liquidations Data
const liqData = $input.first().json;

// Extract liquidation data (structure varies by API response)
const total_liquidation_4h_usd = liqData.total_4h || liqData.total || 0;
const long_liquidations_4h = liqData.long_4h || liqData.long_liquidations || liqData.longs || 0;
const short_liquidations_4h = liqData.short_4h || liqData.short_liquidations || liqData.shorts || 0;

// Build liquidation concentration (top liquidations by size)
const rawLiquidations = liqData.liquidations || liqData.concentration || [];
const liquidation_concentration = rawLiquidations
  .slice(0, 20)
  .map(liq => ({
    price: liq.price || liq.p || 0,
    side: liq.side || liq.type || 'unknown',
    size: liq.size || liq.amount || liq.usd || 0,
    timestamp: liq.time || liq.timestamp || null
  }))
  .sort((a, b) => b.size - a.size);

// Additional metrics
const total_liquidation_1h_usd = liqData.total_1h || 0;
const long_liquidations_1h = liqData.long_1h || 0;
const short_liquidations_1h = liqData.short_1h || 0;

const normalizedLiquidations = {
  total_liquidation_4h_usd,
  long_liquidations_4h,
  short_liquidations_4h,
  liquidation_concentration,
  total_liquidation_1h_usd,
  long_liquidations_1h,
  short_liquidations_1h,
  timestamp: new Date().toISOString()
};

return [{ json: normalizedLiquidations }];

// Signal Detection for OI and Liquidations
const oiResult = $('Normalize OI Data').first().json;
const liqResult = $('Normalize Liquidations').first().json;

const oi_data = oiResult.oi_data;
const liq_data = liqResult;

const signals = {
  oi_signals: [],
  liquidation_signals: [],
  alerts: [],
  regime: 'NEUTRAL',
  timestamp: new Date().toISOString()
};

// OI Regime Analysis
const btcOi = oi_data.find(d => d.symbol === 'BTC');
const ethOi = oi_data.find(d => d.symbol === 'ETH');

// OI Signals
if (btcOi) {
  const { oi_change_1h_pct, regime, price_change_1h_pct } = btcOi;

  if (oi_change_1h_pct > 10) {
    signals.alerts.push({
      type: 'OI_CHANGE_ALERT',
      symbol: 'BTC',
      message: `OI cambio > 10% en 1h: ${oi_change_1h_pct.toFixed(2)}%`,
      severity: 'HIGH'
    });
  }

  if (regime === 'OI_RISING_PRICE') {
    signals.oi_signals.push('TENDENCIA_SANA: OI subiendo + precio subiendo');
    signals.regime = 'OVERHEATED_MOMENTUM';
  } else if (regime === 'OI_FALLING_PRICE') {
    signals.oi_signals.push('CAPITULACION: OI subiendo + precio cayendo');
    signals.regime = 'CAPITULATION';
  } else if (regime === 'SHORT_SQUEEZE') {
    signals.oi_signals.push('SHORT SQUEEZE: OI cayendo + precio subiendo');
    signals.regime = 'SHORT_SQUEEZE';
  } else if (regime === 'DELVERAGING') {
    signals.oi_signals.push('DELEVERAGING: OI cayendo + precio cayendo');
    signals.regime = 'DELEVERAGING';
  }
}

if (ethOi && Math.abs(ethOi.oi_change_1h_pct) > 10) {
  signals.alerts.push({
    type: 'OI_CHANGE_ALERT',
    symbol: 'ETH',
    message: `ALERTA: cambio OI ETH > 10%: ${ethOi.oi_change_1h_pct.toFixed(2)}%`,
    severity: 'MEDIUM'
  });
}

// Liquidation Signals
const longLiq1h = liq_data.long_liquidations_1h || 0;
const shortLiq1h = liq_data.short_liquidations_1h || 0;

if (longLiq1h > 100000000) {
  signals.liquidation_signals.push(`CAPITULACION: Long liqs > $100M en 1h: $${(longLiq1h/1e6).toFixed(1)}M`);
  signals.alerts.push({
    type: 'LIQUIDATION_CAPITULATION',
    message: `Long liquidations > $100M en 1h: $${(longLiq1h/1e6).toFixed(1)}M`,
    severity: 'HIGH'
  });
}

if (shortLiq1h > 50000000) {
  signals.liquidation_signals.push(`SHORT SQUEEZE ACTIVO: Short liqs > $50M en 1h: $${(shortLiq1h/1e6).toFixed(1)}M`);
  signals.alerts.push({
    type: 'SHORT_SQUEEZE_SIGNAL',
    message: `Short liquidations > $50M en 1h: $${(shortLiq1h/1e6).toFixed(1)}M`,
    severity: 'MEDIUM'
  });
}

// Combined regime assessment
if (signals.alerts.length >= 2) {
  signals.regime = 'HIGH_ALERT';
}

return [{ json: signals }];

// Format Summary for Display
const oiResult = $('Normalize OI Data').first().json;
const liqResult = $('Normalize Liquidations').first().json;
const signalsResult = $('Signal Detection').first().json;

const oi_data = oiResult.oi_data;
const liq_data = liqResult;
const signals = signalsResult;

const now = new Date();
const fecha = now.toLocaleDateString('es-ES');
const hora = now.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' });

// Format OI section
let oiSection = `OPEN INTEREST:\n`;
oi_data.slice(0, 5).forEach(coin => {
  const change = coin.oi_change_1h_pct >= 0 ? `+${coin.oi_change_1h_pct.toFixed(2)}` : coin.oi_change_1h_pct.toFixed(2);
  const oiFormatted = coin.total_oi_usd >= 1e9 
    ? `$${(coin.total_oi_usd/1e9).toFixed(1)}B` 
    : `$${(coin.total_oi_usd/1e6).toFixed(1)}M`;

  let regimeNote = '';
  if (coin.regime === 'OI_RISING_PRICE') regimeNote = ' → OI subiendo + precio subiendo = tendencia sana';
  else if (coin.regime === 'OI_FALLING_PRICE') regimeNote = ' → OI subiendo + precio bajando = capitulación';
  else if (coin.regime === 'SHORT_SQUEEZE') regimeNote = ' → OI bajando + precio subiendo = short squeeze';
  else if (coin.regime === 'DELVERAGING') regimeNote = ' → OI bajando + precio bajando = deleveraging';

  oiSection += `${coin.symbol} OI: ${oiFormatted} (${change}% 1h)${regimeNote}\n`;
});

// Check for alerts
const btcAlert = signals.alerts.find(a => a.symbol === 'BTC');
const ethAlert = signals.alerts.find(a => a.symbol === 'ETH');
if (btcAlert) {
  oiSection += `⚠️ ALERTA BTC: ${btcAlert.message}\n`;
}
if (ethAlert) {
  oiSection += `⚠️ ALERTA ETH: ${ethAlert.message}\n`;
}

// Format Liquidations section
const liq4h = liq_data.total_liquidation_4h_usd;
const liq4hFormatted = liq4h >= 1e9 
  ? `$${(liq4h/1e9).toFixed(2)}B` 
  : `$${(liq4h/1e6).toFixed(1)}M`;

let liqSection = `\nLIQUIDACIONES ÚLTIMAS 4H:\n`;
liqSection += `Total: ${liq4hFormatted}\n`;
liqSection += `Longs: $${(liq_data.long_liquidations_4h/1e6).toFixed(1)}M | Shorts: $${(liq_data.short_liquidations_4h/1e6).toFixed(1)}M\n`;

// Format Signals section
let signalsSection = `\nSEÑALES:\n`;
signals.oi_signals.forEach(s => {
  signalsSection += `- ${s}\n`;
});
signals.liquidation_signals.forEach(s => {
  signalsSection += `- ${s}\n`;
});
signalsSection += `\nREGIMEN ACTUAL: ${signals.regime}\n`;

const summary = `OI & LIQUIDACIONES — ${fecha} ${hora}\n\n${oiSection}${liqSection}${signalsSection}`;

return [{ json: { summary, oi_data, liq_data, signals } }];

// Respond to Webhook - OI Snapshot
const fs = require('fs');

let oiData = { error: 'No data available' };
try {
  if (fs.existsSync('/data/cache/crypto_oi_latest.json')) {
    const content = fs.readFileSync('/data/cache/crypto_oi_latest.json', 'utf8');
    oiData = JSON.parse(content);
  }
} catch (e) {
  oiData = { error: e.message };
}

return [{ json: { endpoint: 'oi', data: oiData, timestamp: new Date().toISOString() } }];

// Respond to Webhook - Liquidations
const fs = require('fs');

let liqData = { error: 'No data available' };
try {
  if (fs.existsSync('/data/cache/crypto_liquidations.json')) {
    const content = fs.readFileSync('/data/cache/crypto_liquidations.json', 'utf8');
    liqData = JSON.parse(content);
  }
} catch (e) {
  liqData = { error: e.message };
}

return [{ json: { endpoint: 'liquidations', data: liqData, timestamp: new Date().toISOString() } }];

// Respond to Webhook - Volume
const fs = require('fs');

let volumeData = { error: 'No data available' };
try {
  if (fs.existsSync('/data/cache/crypto_volume.json')) {
    const content = fs.readFileSync('/data/cache/crypto_volume.json', 'utf8');
    volumeData = JSON.parse(content);
  }
} catch (e) {
  volumeData = { error: e.message };
}

return [{ json: { endpoint: 'volume', data: volumeData, timestamp: new Date().toISOString() } }];
